         }
      }
      for (neighbor <- adj(currentNode.toInt)) {
         if ((visited & (1 << neighbor)) == 0) {
            val newVisited = visited | (1 << neighbor)
            val newString = currentString + label(neighbor.toInt)
            dfs(neighbor, newVisited, newString)
         }
      }
   }
